import React, { useState } from 'react';
import htm from 'htm';
import { Download, Printer, MapPin, QrCode } from 'lucide-react';

const html = htm.bind(React.createElement);

export default function QRCodeGenerator() {
  const [location, setLocation] = useState('Sankara Nigeria Limited Head Office');
  const [deviceUuidRequired, setDeviceUuidRequired] = useState(true);

  const qrData = JSON.stringify({
    workplace: location,
    device_uuid_required: deviceUuidRequired,
    timestamp: new Date().toISOString()
  });

  const qrImageUrl = `https://api.qrserver.com/v1/create-qr-code/?size=300x300&data=${encodeURIComponent(qrData)}`;

  const handlePrint = () => {
    const printWindow = window.open('', '_blank');
    printWindow.document.write(`
      <html>
        <head>
          <title>Workplace Attendance QR Code</title>
          <style>
            body {
              font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
              text-align: center;
              padding: 40px;
              color: #1F2937;
            }
            .card {
              border: 3px solid #6366F1;
              border-radius: 20px;
              padding: 40px;
              max-width: 500px;
              margin: 0 auto;
              box-shadow: 0 10px 15px -3px rgba(0, 0, 0, 0.1);
            }
            h1 {
              color: #4F46E5;
              margin-top: 0;
            }
            .qr-img {
              margin: 20px 0;
              width: 250px;
              height: 250px;
            }
            .footer {
              font-size: 0.875rem;
              color: #6B7280;
              margin-top: 20px;
            }
          </style>
        </head>
        <body>
          <div class="card">
            <h1>Sankara Attendance Portal</h1>
            <p>Scan this QR code using the Sankara Staff App to clock in/out.</p>
            <img class="qr-img" src="${qrImageUrl}" alt="Attendance QR Code" />
            <h3>Location: ${location}</h3>
            <p class="footer">Verification mode: ${deviceUuidRequired ? 'Anti-Proxy Protected' : 'Standard'}</p>
          </div>
          <script>
            window.onload = function() {
              window.print();
            }
          </script>
        </body>
      </html>
    `);
    printWindow.document.close();
  };

  return html`
    <div>
      <header style=${{ marginBottom: '2rem' }}>
        <h1>QR Code Attendance Generator</h1>
        <p>Generate secure, location-locked QR codes for workplace attendance scanning.</p>
      </header>

      <div style=${{ display: 'grid', gridTemplateColumns: '1.2fr 1fr', gap: '2rem', alignItems: 'start' }}>

        <div className="glass-panel" style=${{ padding: '2rem' }}>
          <h2 style=${{ marginTop: 0, marginBottom: '1.5rem', display: 'flex', alignItems: 'center', gap: '8px' }}>
            <${QrCode} size=${24} style=${{ color: 'var(--primary-color)' }} /> QR Configuration
          </h2>

          <div style=${{ marginBottom: '1.5rem' }}>
            <label style=${{ display: 'block', marginBottom: '0.5rem', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>Workplace Location Name</label>
            <div style=${{ position: 'relative' }}>
              <${MapPin} size=${18} style=${{ position: 'absolute', left: '12px', top: '50%', transform: 'translateY(-50%)', color: 'var(--text-secondary)' }} />
              <input 
                type="text" 
                className="input-field" 
                style=${{ paddingLeft: '2.5rem' }}
                value=${location}
                onChange=${e => setLocation(e.target.value)}
              />
            </div>
          </div>

          <div style=${{ marginBottom: '1.5rem', display: 'flex', alignItems: 'center', gap: '10px' }}>
            <input 
              type="checkbox" 
              id="device_uuid" 
              checked=${deviceUuidRequired}
              onChange=${e => setDeviceUuidRequired(e.target.checked)}
              style=${{ width: '18px', height: '18px', cursor: 'pointer' }}
            />
            <label htmlFor="device_uuid" style=${{ fontSize: '0.95rem', cursor: 'pointer', color: 'white' }}>
              Enable Anti-Proxy Verification (Device Lock)
            </label>
          </div>

          <p style=${{ fontSize: '0.825rem', color: 'var(--text-secondary)', lineHeight: '1.4', marginBottom: '2rem' }}>
            When enabled, employees scanning this code must use their registered personal device. Scans from mismatching devices will be logged with a <strong>Proxy Warning</strong> badge.
          </p>

          <button className="btn btn-primary" onClick=${handlePrint} style=${{ width: '100%', display: 'flex', justifyContent: 'center', alignItems: 'center', gap: '8px' }}>
            <${Printer} size=${18} /> Print Attendance Poster
          </button>
        </div>

        <div className="glass-panel" style=${{ padding: '2rem', textAlign: 'center', display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
          <h3 style=${{ marginTop: 0, marginBottom: '1.5rem' }}>Live QR Display</h3>

          <div style=${{ background: 'white', padding: '1.5rem', borderRadius: '16px', display: 'inline-block', boxShadow: '0 10px 25px rgba(0,0,0,0.2)' }}>
            <img src=${qrImageUrl} style=${{ width: '240px', height: '240px', display: 'block' }} alt="QR Code" />
          </div>

          <p style=${{ marginTop: '1.5rem', fontWeight: 500, fontSize: '1.1rem', color: 'white' }}>
            ${location}
          </p>

          <span className="badge badge-success" style=${{ marginTop: '0.5rem' }}>
            ${deviceUuidRequired ? 'Anti-Proxy Enabled' : 'Standard Check-in'}
          </span>
        </div>

      </div>
    </div>
  `;
}
